public int maxTastiness(int[] price, int k) {
    Arrays.sort(price);
    int max_tastiness = 0;
    for (int i = 0; i < price.length - k + 1; i++) {
        int min_diff = Integer.MAX_VALUE;
        for (int j = i; j < i + k - 1; j++) {
            min_diff = Math.min(min_diff, price[j + 1] - price[j]);
        }
        max_tastiness = Math.max(max_tastiness, min_diff);
    }

    return max_tastiness;
}
